#[derive(Debug)]
struct Rectangle {
    width: u32,
    height: u32,
}

impl Rectangle {
    fn square(size: u32) -> Self {
        Self { width: size, height: size }
    }

    fn area(&self) -> u32 {
        self.width * self.height
    }

    fn can_hold(&self, other: &Rectangle) -> bool {
        self.width > other.width && self.height > other.height
    }
}

fn main() {
    let rect1 = Rectangle { width: 30, height: 50 };
    println!("矩形: {:?}", rect1);
    println!("矩形面积: {}", rect1.area());

    let rect2 = Rectangle { width: 10, height: 40 };
    println!("rect1 能容纳 rect2? {}", rect1.can_hold(&rect2));

    let sq = Rectangle::square(20);
    println!("正方形面积: {}", sq.area());
}

enum Message {
    Quit,
    Move { x: i32, y: i32 },
    Write(String),
}

fn main() {
    let msg = Message::Move { x: 10, y: 20 };

    match msg {
        Message::Quit => println!("退出"),
        Message::Move { x, y } => println!("移动到 ({}, {})", x, y),
        Message::Write(text) => println!("写入: {}", text),
    }

    let some_number = Some(5);
    if let Some(n) = some_number {
        println!("值是: {}", n);
    }

    let absent: Option<i32> = None;
    println!("absent: {:?}", absent);

    // 处理 Option 的常用模式
    let val = Some(7);
    match val {
        Some(n) if n > 5 => println!("大于 5: {}", n),
        Some(_) => println!("不大于 5"),
        None => println!("没有值"),
    }
}

fn main() {
    match divide(10, 2) {
        Ok(n) => println!("10 / 2 = {}", n),
        Err(e) => println!("错误: {}", e),
    }

    match divide(10, 0) {
        Ok(n) => println!("10 / 0 = {}", n),
        Err(e) => println!("错误: {}", e),
    }

    let safe = divide(10, 0).unwrap_or(0);
    println!("unwrap_or 结果: {}", safe);

    match safe_divide(10, 0) {
        Ok(n) => println!("传播后结果: {}", n),
        Err(e) => println!("传播错误: {}", e),
    }
}

fn divide(a: i32, b: i32) -> Result<i32, String> {
    if b == 0 {
        Err(String::from("除数不能为零"))
    } else {
        Ok(a / b)
    }
}

fn safe_divide(a: i32, b: i32) -> Result<i32, String> {
    let r = divide(a, b)?;
    Ok(r * 2)
}

